output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?narratorLabel WHERE {
  ?game wdt:P31 wd:Q7889 ; wdt:P123 wd:Q2654839 ; wdt:P154 wd:Q3094364 ; wdt:P2438 ?narrator .
  OPTIONAL {
    ?narrator rdfs:label ?narratorLabel .
    FILTER(lang(?narratorLabel) = "en")
  }
}

